# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)

# In-memory storage for labels
labels = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    # Store the label with the annotator ID
    labels[image_id].append({'label': label, 'annotator_id': annotator_id})
    return jsonify({'message': 'Label received'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    
    for image_id, label_data in labels.items():
        label_counts = defaultdict(int)
        
        for entry in label_data:
            label_counts[entry['label']] += 1
        
        # Majority voting
        majority_label = max(label_counts, key=label_counts.get)
        aggregated_labels[image_id] = majority_label
    
    return jsonify(aggregated_labels), 200

@app.route('/train', methods=['POST'])
def train_model():
    # Placeholder for model training logic
    # Here you would implement your model training using the aggregated labels
    aggregated_labels = aggregate_labels().get_json()
    
    # Convert aggregated labels to a format suitable for training
    training_data = []
    for image_id, label in aggregated_labels.items():
        training_data.append({'image_id': image_id, 'label': label})
    
    # Simulate model training
    with open('training_data.json', 'w') as f:
        json.dump(training_data, f)
    
    return jsonify({'message': 'Model trained on labeled data'}), 200

if __name__ == '__main__':
    app.run(debug=True)